# Custom Pydantic-AI Capability with Conditional Tool Visibility

Here's a practical implementation that hides tools based on runtime conditions and supports `from_spec` deserialization:

```python
from pydantic_ai import Agent
from pydantic import BaseModel
from typing import Any, Optional, Callable
import inspect

class ToolAccessControl(BaseModel):
    """Runtime configuration for tool visibility"""
    enabled_tools: set[str]
    is_admin: bool = False

    @classmethod
    def from_spec(cls, spec: dict[str, Any]) -> 'ToolAccessControl':
        """Deserialize from specification"""
        return cls(**spec)


class ConditionalToolCapability:
    """Capability that conditionally exposes tools"""

    def __init__(self, access_control: ToolAccessControl):
        self.access_control = access_control

    def _should_expose(self, tool_name: str) -> bool:
        """Determine if tool should be visible"""
        if tool_name not in self.access_control.enabled_tools:
            return False

        # Admin-only check
        if tool_name.startswith('admin_') and not self.access_control.is_admin:
            return False

        return True

    def get_available_tools(self) -> dict[str, Callable]:
        """Return only enabled tools"""
        tools = {}
        for name, method in inspect.getmembers(self, predicate=inspect.ismethod):
            if not name.startswith('_') and self._should_expose(name):
                tools[name] = method
        return tools

    # Tool methods
    def list_data(self) -> str:
        """List all data"""
        return "data1, data2, data3"

    def admin_delete_data(self, item_id: str) -> str:
        """Delete data (admin only)"""
        return f"Deleted {item_id}"

    def admin_reset_system(self) -> str:
        """Reset system (admin only)"""
        return "System reset"

    @classmethod
    def from_spec(cls, spec: dict[str, Any]) -> 'ConditionalToolCapability':
        """Deserialize from specification with tool visibility config"""
        access_control = ToolAccessControl.from_spec(spec.get('access_control', {}))
        return cls(access_control=access_control)


def create_agent(access_control: ToolAccessControl) -> Agent:
    """Create agent with conditionally visible tools"""
    capability = ConditionalToolCapability(access_control)
    agent = Agent(model='gpt-4')

    # Register only available tools
    for tool_name, tool_method in capability.get_available_tools().items():
        agent.tool(description=tool_method.__doc__)(tool_method)

    return agent


# Usage Examples
# Regular user - limited access
user_config = ToolAccessControl(
    enabled_tools={'list_data'},
    is_admin=False
)
user_agent = create_agent(user_config)

# Admin user - full access
admin_config = ToolAccessControl(
    enabled_tools={'list_data', 'admin_delete_data', 'admin_reset_system'},
    is_admin=True
)
admin_agent = create_agent(admin_config)

# Load from spec
spec = {
    'access_control': {
        'enabled_tools': ['list_data', 'admin_delete_data'],
        'is_admin': True
    }
}
capability = ConditionalToolCapability.from_spec(spec)
agent = create_agent(capability.access_control)
```

## Key Features:

1. **Runtime Conditions**: `ToolAccessControl` defines visibility rules
2. **from_spec Support**: Both classes implement `from_spec()` for deserialization
3. **Dynamic Registration**: Only enabled tools are registered with the agent
4. **Admin Checks**: Tools prefixed with `admin_` require `is_admin=True`

You can extend the `_should_expose()` method with custom logic (user roles, feature flags, etc.) as needed.

